def connection_handler(self, conn, address):
    socket_file = conn.makefile('rwb')
    while True:
        try:
            data = self._protocol.handle_request(socket_file)
        except Disconnect:
            break
        try:
            resp = self.get_response(data)
        except CommandError as exc:
            resp = Error(exc.args[0])
        self._protocol.write_response(socket_file, resp)

def handle_request(self, socket_file):
    first_byte = socket_file.read(1)
    if not first_byte:
        raise Disconnect()
    return self.handlers[first_byte](socket_file)

def handle_string(self, socket_file):
    length = int(socket_file.readline().rstrip('\r\n'))
    if length == -1:
        return None
    length += 2
    return socket_file.read(length)[:-2]

def get_response(self, data):
    if not isinstance(data, list):
        data = data.split()
    command = data[0].upper()
    if command not in self._commands:
        raise CommandError('Unrecognized command: %s' % command)
    return self._commands[command](*data[1:])

def read_from_tokens(tokens: list):
    if len(tokens) == 0:
        raise SyntaxError('unexpected EOF')
    token = tokens.pop(0)
    if token == '(':
        L = []
        while tokens[0] != ')':
            L.append(read_from_tokens(tokens))
        tokens.pop(0)
        return L
    elif token == ')':
        raise SyntaxError('unexpected )')
    else:
        return atom(token)

def eval(x, env):
    if isinstance(x, str):
        return env[x]
    elif isinstance(x, (int, float)):
        return x
    op, *args = x
    if op == 'define':
        (_, symbol, exp) = x
        env[symbol] = eval(exp, env)
    elif op == 'if':
        (_, test, conseq, alt) = x
        branch = conseq if eval(test, env) else alt
        return eval(branch, env)
    else:
        proc = eval(op, env)
        vals = [eval(arg, env) for arg in args]
        return proc(*vals)

class JsonDecoder:
    def __init__(self, s: str):
        self.s = s
        self.i = 0

    def decode(self):
        self.skip_ws()
        v = self.decode_value()
        self.skip_ws()
        if self.i != len(self.s):
            raise ValueError('trailing data')
        return v

def decode_value(self):
    ch = self.peek()
    if ch == 'n': return self.decode_null()
    if ch in 'tf': return self.decode_bool()
    if ch == '"': return self.decode_string()
    if ch == '[': return self.decode_array()
    if ch == '{': return self.decode_object()
    if ch in '-0123456789': return self.decode_number()
    raise ValueError(f'unexpected {ch!r}')

def decode_string(self):
    assert self.next() == '"'
    out = []
    while True:
        ch = self.next()
        if ch == '"': break
        if ch == '\\':
            esc = self.next()
            out.append({'n':'\n','t':'\t','r':'\r','\\':'\\','"':'"'}.get(esc, esc))
        else:
            out.append(ch)
    return ''.join(out)
